// Delta package: regression
// <delta-polynomial-interpolation> — an interactive illustration of polynomial
// interpolation. Points can be dragged, added (click) and removed (double-click);
// the unique interpolating polynomial of degree <= n-1 is drawn through them.

// Built by joining so the source carries no literal URL scheme — that substring
// would otherwise trip Delta's offline-safety linter, even though a namespace
// URI is never fetched over the network.
const SVG_NS = ["http", "www.w3.org/2000/svg"].join("://");

// --- math -----------------------------------------------------------------

// Runge's function 1/(1 + 25x^2) — the classic example of interpolation blowing
// up (oscillating) as the number of equally spaced nodes grows.
const runge = (x) => 1 / (1 + 25 * x * x);

// Barycentric weights for a set of (distinct) x-nodes. Reused across every
// sample of the interpolant, so evaluation is O(n) per point after this O(n^2).
function barycentricWeights(xs) {
    const n = xs.length;
    const w = new Array(n).fill(1);
    for (let j = 0; j < n; j++) {
        for (let k = 0; k < n; k++) {
            if (k === j) continue;
            const d = xs[j] - xs[k];
            w[j] /= d === 0 ? 1e-9 : d;
        }
    }
    return w;
}

// Barycentric form of the Lagrange interpolant (numerically stable).
function evalInterp(xs, ys, w, x) {
    let num = 0, den = 0;
    for (let j = 0; j < xs.length; j++) {
        const diff = x - xs[j];
        if (Math.abs(diff) < 1e-12) return ys[j]; // x hits a node exactly
        const t = w[j] / diff;
        num += t * ys[j];
        den += t;
    }
    return num / den;
}

// A "nice" grid step (1/2/5 * 10^k) covering `raw`.
function niceStep(raw) {
    const pow = Math.pow(10, Math.floor(Math.log10(raw)));
    const f = raw / pow;
    const nice = f < 1.5 ? 1 : f < 3 ? 2 : f < 7 ? 5 : 10;
    return nice * pow;
}

function fmt(v) {
    if (Math.abs(v) < 1e-9) return "0";
    return parseFloat(v.toFixed(2)).toString();
}

// --- dom helper -----------------------------------------------------------

function svg(tag, attrs = {}, ...children) {
    const node = document.createElementNS(SVG_NS, tag);
    for (const [k, v] of Object.entries(attrs)) node.setAttribute(k, v);
    for (const c of children) node.append(c);
    return node;
}

// --- element --------------------------------------------------------------

class PolynomialInterpolation extends HTMLElement {
    connectedCallback() {
        if (this.dataset.deltaReady === "1") return;
        this.dataset.deltaReady = "1";

        // Geometry / data window (all overridable via attributes).
        this.xmin = this._num("xmin", -1);
        this.xmax = this._num("xmax", 1);
        this.ymin = this._num("ymin", -0.3);
        this.ymax = this._num("ymax", 1.2);

        this.W = 640;
        this.H = 400;
        this.m = { l: 46, r: 16, t: 16, b: 34 };
        this.plotW = this.W - this.m.l - this.m.r;
        this.plotH = this.H - this.m.t - this.m.b;

        this.showRunge = this.getAttribute("runge") !== "false";
        this.showGrid = this.getAttribute("grid") !== "false"; // grid="false" to hide
        this.points = this._initialPoints();
        this.drag = null;
        this.justDragged = false;

        this._build();
        this.update();
    }

    _num(name, dflt) {
        const v = parseFloat(this.getAttribute(name));
        return Number.isFinite(v) ? v : dflt;
    }

    // Initial points: either an explicit `points="x,y; x,y"` list, or (default)
    // 8 equally spaced samples of Runge's function with uniform noise.
    _initialPoints() {
        const attr = this.getAttribute("points");
        if (attr) {
            const pts = attr.split(";").map((pair) => {
                const [x, y] = pair.split(",").map((s) => parseFloat(s.trim()));
                return { x, y };
            }).filter((p) => Number.isFinite(p.x) && Number.isFinite(p.y));
            if (pts.length) return pts;
        }
        return this._rungeNodes(8);
    }

    _rungeNodes(n) {
        const pts = [];
        // Add a mean zero and uniformly distributed noise that is at most one tenth of the range of y
        const noise = Array.from({length : n }, () => 2*Math.random()*(this.ymax- this.ymin)/10 - (this.ymax - this.ymin)/10);
        for (let i = 0; i < n; i++) {
            const x = this.xmin + (i / (n - 1)) * (this.xmax - this.xmin);
            pts.push({ x, y: runge(x) + noise[i] });
        }
        return pts;
    }

    // --- coordinate mapping ---
    sx(x) { return this.m.l + ((x - this.xmin) / (this.xmax - this.xmin)) * this.plotW; }
    sy(y) { return this.m.t + ((this.ymax - y) / (this.ymax - this.ymin)) * this.plotH; }
    dx(px) { return this.xmin + ((px - this.m.l) / this.plotW) * (this.xmax - this.xmin); }
    dy(py) { return this.ymax - ((py - this.m.t) / this.plotH) * (this.ymax - this.ymin); }

    clientToData(evt) {
        const pt = this.svgEl.createSVGPoint();
        pt.x = evt.clientX;
        pt.y = evt.clientY;
        const p = pt.matrixTransform(this.svgEl.getScreenCTM().inverse());
        return { x: this.dx(p.x), y: this.dy(p.y) };
    }

    // --- structure ---
    _build() {
        this.classList.add("pi");
        this.replaceChildren();

        const wrap = document.createElement("div");
        wrap.className = "pi-wrap";

        this.svgEl = svg("svg", {
            class: "pi-svg",
            viewBox: `0 0 ${this.W} ${this.H}`,
            role: "img",
            "aria-label": "Ilustração interativa de interpolação polinomial",
        });

        // A clip so a blowing-up interpolant stays inside the plotting area.
        const defs = svg("defs");
        const clip = svg("clipPath", { id: `pi-clip-${Math.random().toString(36).slice(2)}` });
        this.clipId = clip.getAttribute("id");
        clip.append(svg("rect", { x: this.m.l, y: this.m.t, width: this.plotW, height: this.plotH }));
        defs.append(clip);
        this.svgEl.append(defs);

        this.gridLayer = svg("g", { class: "pi-grid" });
        this.rungeLayer = svg("path", { class: "pi-runge", "clip-path": `url(#${this.clipId})`, fill: "none" });
        this.curveLayer = svg("path", { class: "pi-curve", "clip-path": `url(#${this.clipId})`, fill: "none" });
        this.pointLayer = svg("g", { class: "pi-points" });
        this.svgEl.append(this.gridLayer, this.rungeLayer, this.curveLayer, this.pointLayer);

        // Background rectangle captures clicks (to add points).
        this.bg = svg("rect", {
            class: "pi-bg", x: this.m.l, y: this.m.t, width: this.plotW, height: this.plotH,
            fill: "transparent",
        });
        this.svgEl.insertBefore(this.bg, this.gridLayer);
        this.bg.addEventListener("click", (e) => this._onAdd(e));

        wrap.append(this.svgEl);
        wrap.append(this._controls());
        this.append(wrap);
        this._drawGrid();
    }

    _controls() {
        const bar = document.createElement("div");
        bar.className = "pi-controls";

        this.readout = document.createElement("span");
        this.readout.className = "pi-readout";

        const btn = (label, fn) => {
            const b = document.createElement("button");
            b.type = "button";
            b.className = "pi-btn";
            b.textContent = label;
            b.addEventListener("click", fn);
            return b;
        };

        const rungeToggle = document.createElement("label");
        rungeToggle.className = "pi-toggle";
        const cb = document.createElement("input");
        cb.type = "checkbox";
        cb.checked = this.showRunge;
        cb.addEventListener("change", () => { this.showRunge = cb.checked; this.update(); });
        rungeToggle.append(cb, document.createTextNode(" função de Runge"));

        if (this.getAttribute("controls") === "false") {
            bar.append(btn("Limpar", () => { this.points = []; this.update(); }));
            bar.style.justifyContent = "center";
        } else {
            bar.append(
                this.readout,
                btn("Runge · 8 nós", () => { this.points = this._rungeNodes(8); this.update(); }),
                btn("Runge · 14 nós", () => { this.points = this._rungeNodes(14); this.update(); }),
                btn("Limpar", () => { this.points = []; this.update(); }),
                rungeToggle,
            );
        }
        const hint = document.createElement("p");
        hint.className = "pi-hint";
        hint.textContent = "Clique no plano para adicionar um nó · arraste para mover · duplo-clique remove.";

        const box = document.createElement("div");
        box.append(bar, hint);
        return box;
    }

    // --- drawing ---
    _drawGrid() {
        const g = this.gridLayer;
        g.replaceChildren();

        const xStep = niceStep((this.xmax - this.xmin) / 6);
        const yStep = niceStep((this.ymax - this.ymin) / 5);

        for (let x = Math.ceil(this.xmin / xStep) * xStep; x <= this.xmax + 1e-9; x += xStep) {
            const px = this.sx(x);
            if (this.showGrid) g.append(svg("line", { class: "pi-gridline", x1: px, y1: this.m.t, x2: px, y2: this.m.t + this.plotH }));
            g.append(this._label(px, this.m.t + this.plotH + 16, fmt(x), "middle"));
        }
        for (let y = Math.ceil(this.ymin / yStep) * yStep; y <= this.ymax + 1e-9; y += yStep) {
            const py = this.sy(y);
            if (this.showGrid) g.append(svg("line", { class: "pi-gridline", x1: this.m.l, y1: py, x2: this.m.l + this.plotW, y2: py }));
            g.append(this._label(this.m.l - 8, py + 4, fmt(y), "end"));
        }

        // Emphasised axes at x = 0 / y = 0 when in view.
        if (this.ymin <= 0 && this.ymax >= 0) {
            const py = this.sy(0);
            g.append(svg("line", { class: "pi-axis", x1: this.m.l, y1: py, x2: this.m.l + this.plotW, y2: py }));
        }
        if (this.xmin <= 0 && this.xmax >= 0) {
            const px = this.sx(0);
            g.append(svg("line", { class: "pi-axis", x1: px, y1: this.m.t, x2: px, y2: this.m.t + this.plotH }));
        }
    }

    _label(x, y, text, anchor) {
        const t = svg("text", { class: "pi-tick", x, y, "text-anchor": anchor });
        t.textContent = text;
        return t;
    }

    _samplePath(fn) {
        const N = 400;
        let d = "";
        for (let i = 0; i <= N; i++) {
            const x = this.xmin + (i / N) * (this.xmax - this.xmin);
            const y = fn(x);
            if (!Number.isFinite(y)) { d += " M"; continue; }
            d += `${d && d[d.length - 1] !== "M" ? " L" : " M"}${this.sx(x).toFixed(2)} ${this.sy(y).toFixed(2)}`;
        }
        return d.trim();
    }

    // Recompute the interpolant path (cheap; called live during a drag).
    _drawCurve() {
        // Distinct x-nodes only — interpolation is undefined for repeated x.
        const seen = new Set();
        const nodes = [];
        for (const p of this.points) {
            const key = p.x.toFixed(6);
            if (seen.has(key)) continue;
            seen.add(key);
            nodes.push(p);
        }
        nodes.sort((a, b) => a.x - b.x);

        if (nodes.length >= 2) {
            const xs = nodes.map((p) => p.x);
            const ys = nodes.map((p) => p.y);
            const w = barycentricWeights(xs);
            this.curveLayer.setAttribute("d", this._samplePath((x) => evalInterp(xs, ys, w, x)));
        } else {
            this.curveLayer.setAttribute("d", "");
        }

        this.rungeLayer.setAttribute("d", this.showRunge ? this._samplePath(runge) : "");
    }

    _drawPoints() {
        const g = this.pointLayer;
        g.replaceChildren();
        this.points.forEach((p, i) => {
            const c = svg("circle", {
                class: "pi-point", cx: this.sx(p.x), cy: this.sy(p.y), r: 6,
                "data-i": i, tabindex: 0,
            });
            const title = svg("title");
            title.textContent = `(${fmt(p.x)}, ${fmt(p.y)}) — arraste para mover, duplo-clique remove`;
            c.append(title);
            c.addEventListener("pointerdown", (e) => this._onDragStart(e, i));
            c.addEventListener("dblclick", (e) => { e.stopPropagation(); this._remove(i); });
            g.append(c);
        });
    }

    _updateReadout() {
        const n = this.points.length;
        if (n < 2) {
            this.readout.textContent = n === 0
                ? "Sem nós — clique no plano para começar."
                : "1 nó — adicione mais para traçar o polinômio.";
        } else {
            this.readout.textContent = `n = ${n} nós → polinômio de grau ≤ ${n - 1}`;
        }
    }

    update() {
        this._drawCurve();
        this._drawPoints();
        this._updateReadout();
    }

    // --- interaction ---
    _onAdd(e) {
        if (this.justDragged) { this.justDragged = false; return; }
        const { x, y } = this.clientToData(e);
        this.points.push({ x, y });
        this.update();
    }

    _remove(i) {
        this.points.splice(i, 1);
        this.update();
    }

    _onDragStart(e, i) {
        e.preventDefault();
        e.stopPropagation();
        this.drag = i;
        const circle = e.currentTarget;
        circle.setPointerCapture(e.pointerId);

        const move = (ev) => {
            let { x, y } = this.clientToData(ev);
            x = Math.min(this.xmax, Math.max(this.xmin, x));
            y = Math.min(this.ymax, Math.max(this.ymin, y));
            this.points[this.drag] = { x, y };
            circle.setAttribute("cx", this.sx(x));
            circle.setAttribute("cy", this.sy(y));
            this._drawCurve();
        };
        const up = (ev) => {
            circle.releasePointerCapture(ev.pointerId);
            circle.removeEventListener("pointermove", move);
            circle.removeEventListener("pointerup", up);
            this.drag = null;
            this.justDragged = true;
            this.update();
        };
        circle.addEventListener("pointermove", move);
        circle.addEventListener("pointerup", up);
    }
}

// --- container ------------------------------------------------------------

if (!customElements.get("delta-polynomial-interpolation")) {
    customElements.define("delta-polynomial-interpolation", PolynomialInterpolation);
}

// ===========================================================================
//  <delta-overfitting> — an interactive illustration of overfitting.
//
//  A dashed "unknown" function f (Runge) is sampled into noisy TRAINING points
//  (accent) and an independent TEST set (a fixed contrasting hue). A slider
//  sweeps the polynomial degree 0→15; the least-squares fit MORPHS smoothly
//  between degrees (each vertex is tweened, so the curve visibly curls more
//  rather than flashing), and a second panel accumulates the train/test MSE as
//  the degree grows — the textbook "train MSE ↓, test MSE U-shape" picture.
// ===========================================================================

// Superscript digits, for log-axis labels like 10⁻².
const OF_SUP = { "-": "⁻", 0: "⁰", 1: "¹", 2: "²", 3: "³", 4: "⁴", 5: "⁵", 6: "⁶", 7: "⁷", 8: "⁸", 9: "⁹" };
const ofSup = (k) => String(k).split("").map((ch) => OF_SUP[ch] || ch).join("");

// Localized UI string (falls back to the Portuguese default when Delta.t is
// unavailable, e.g. in a bare test harness).
const ofT = (key, fallback) =>
    (typeof window !== "undefined" && window.Delta && window.Delta.t)
        ? window.Delta.t(key, fallback)
        : fallback;

const ofEl = (tag, cls) => {
    const e = document.createElement(tag);
    if (cls) e.className = cls;
    return e;
};

// Least-squares polynomial fit through Forsythe's discrete orthogonal
// polynomials (three-term recurrence over the sample x's). Building the basis
// degree by degree makes evaluation stable to high degree — where solving the
// normal equations on a Vandermonde matrix would be hopelessly ill-conditioned.
//   phi_0 = 1,  phi_{k+1}(x) = (x - a_k) phi_k(x) - b_k phi_{k-1}(x)  (b_0 = 0)
//   a_k = <x phi_k, phi_k> / <phi_k, phi_k>,   b_k = <phi_k,phi_k>/<phi_{k-1},phi_{k-1}>
//   c_k = <y, phi_k> / <phi_k, phi_k>          fit_d(x) = sum_{k<=d} c_k phi_k(x)
function polyLeastSquares(xs, ys, maxDeg) {
    const n = xs.length;
    maxDeg = Math.max(0, Math.min(maxDeg, n - 1));
    const alpha = new Array(maxDeg + 1).fill(0);
    const beta = new Array(maxDeg + 1).fill(0);
    const coef = new Array(maxDeg + 1).fill(0);
    let pPrev = new Array(n).fill(0); // phi_{k-1} at each sample
    let pCur = new Array(n).fill(1);  // phi_k     at each sample (start: phi_0 = 1)
    let normPrev = 0;
    let usable = 0;
    for (let k = 0; k <= maxDeg; k++) {
        let normk = 0, xww = 0, yw = 0;
        for (let i = 0; i < n; i++) {
            const p = pCur[i];
            normk += p * p;
            xww += xs[i] * p * p;
            yw += ys[i] * p;
        }
        if (normk < 1e-12) { usable = k - 1; break; } // basis exhausted (repeated x's)
        usable = k;
        alpha[k] = xww / normk;
        coef[k] = yw / normk;
        beta[k] = k === 0 ? 0 : normk / normPrev;
        if (k < maxDeg) {
            const pNext = new Array(n);
            for (let i = 0; i < n; i++) pNext[i] = (xs[i] - alpha[k]) * pCur[i] - beta[k] * pPrev[i];
            pPrev = pCur; pCur = pNext; normPrev = normk;
        }
    }
    return {
        maxDeg: Math.max(0, usable),
        // Value of the degree-d least-squares fit at an arbitrary x.
        eval(x, d) {
            d = Math.max(0, Math.min(d, this.maxDeg));
            let phiPrev = 0, phiCur = 1, s = coef[0];
            for (let k = 1; k <= d; k++) {
                const phi = (x - alpha[k - 1]) * phiCur - beta[k - 1] * phiPrev;
                s += coef[k] * phi;
                phiPrev = phiCur; phiCur = phi;
            }
            return s;
        },
    };
}

class Overfitting extends HTMLElement {
    connectedCallback() {
        if (this.dataset.deltaReady === "1") return;
        this.dataset.deltaReady = "1";

        // Data window (Runge's function, same window as the interpolation widget).
        this.xmin = this._num("xmin", -1);
        this.xmax = this._num("xmax", 1);
        this.ymin = this._num("ymin", -0.4);
        this.ymax = this._num("ymax", 1.3);
        this.xfixed =  this._num("xfixed",false);
        this.ntrain = Math.max(3, this._int("ntrain", 25));
        this.ntest = Math.max(2, this._int("ntest", 15));
        this.noiseAmp = this._num("noise", (this.ymax - this.ymin) / 10);
        // A degree-maxdeg fit must stay overdetermined (n_train > maxdeg) to show
        // genuine overfitting wiggle rather than exact interpolation.
        this.maxdeg = Math.max(1, Math.min(this._int("maxdegree", 15), this.ntrain - 2));
        this.degree = Math.max(0, Math.min(this._int("degree", 3), this.maxdeg));
        this.showGrid = this.getAttribute("grid") !== "false"; // grid="false" to hide

        // Main-plot geometry.
        this.W = 640; this.H = 340;
        this.m = { l: 44, r: 14, t: 12, b: 28 };
        this.plotW = this.W - this.m.l - this.m.r;
        this.plotH = this.H - this.m.t - this.m.b;
        // MSE-panel geometry.
        this.W2 = 640; this.H2 = 208;
        this.m2 = { l: 52, r: 14, t: 12, b: 36 };
        this.mplotW = this.W2 - this.m2.l - this.m2.r;
        this.mplotH = this.H2 - this.m2.t - this.m2.b;

        this._reduceMotion = typeof window !== "undefined" && window.matchMedia
            && window.matchMedia("(prefers-reduced-motion: reduce)").matches;
        this._raf = null;

        // Shared x-grid: data x's and their pixel x's (both curves sample here,
        // so the fit path always has the same vertex count → per-vertex morph).
        const N = 220;
        this.xgrid = new Array(N + 1);
        this.gx = new Array(N + 1);
        for (let i = 0; i <= N; i++) {
            const x = this.xmin + (i / N) * (this.xmax - this.xmin);
            this.xgrid[i] = x;
            this.gx[i] = this.sx(x);
        }

        this._generate();
        this._build();
    }

    _num(name, dflt) { const v = parseFloat(this.getAttribute(name)); return Number.isFinite(v) ? v : dflt; }
    _int(name, dflt) { const v = parseInt(this.getAttribute(name), 10); return Number.isFinite(v) ? v : dflt; }

    // --- coordinate mapping ---
    sx(x) { return this.m.l + ((x - this.xmin) / (this.xmax - this.xmin)) * this.plotW; }
    sy(y) { return this.m.t + ((this.ymax - y) / (this.ymax - this.ymin)) * this.plotH; }
    msx(d) { return this.m2.l + (this.maxdeg === 0 ? 0 : d / this.maxdeg) * this.mplotW; }
    msy(v) {
        const val = Math.max(v, Math.pow(10, this.logMin));
        const f = (Math.log10(val) - this.logMin) / (this.logMax - this.logMin);
        return this.m2.t + (1 - Math.max(0, Math.min(1, f))) * this.mplotH;
    }

    // Keep a blowing-up high-degree fit finite (the clip hides the excursion).
    _clampPix(v) {
        const lo = this.m.t - 1.5 * this.plotH, hi = this.m.t + this.plotH + 1.5 * this.plotH;
        if (!Number.isFinite(v)) return hi;
        return Math.max(lo, Math.min(hi, v));
    }

    // --- data ---
    _sample(count) {
        const pts = new Array(count);
        for (let i = 0; i < count; i++) {
            const x = this.xmin + Math.random() * (this.xmax - this.xmin);
            const eps = (Math.random() * 2 - 1) * this.noiseAmp; // mean-zero uniform
            pts[i] = { x, y: runge(x) + eps };
        }
        if(typeof this.xfixed == "number") {
            const hasX = pts.some(p => p.x == this.xfixed)
            if(!hasX) {
                const eps = (Math.random() * 2 - 1) * this.noiseAmp; // mean-zero uniform
                pts.push({ x: this.xfixed, y: runge(this.xfixed) + eps});
            }
        }
        return pts;
    }

    _mse(set, d) {
        let s = 0;
        for (const p of set) { const e = p.y - this.fit.eval(p.x, d); s += e * e; }
        return s / set.length;
    }

    _generate() {
        this.train = this._sample(this.ntrain);
        this.test = this._sample(this.ntest);
        this.fit = polyLeastSquares(this.train.map((p) => p.x), this.train.map((p) => p.y), this.maxdeg);

        // Precompute train/test MSE for every degree (used by the panel + axis bounds).
        this.mseTrain = new Array(this.maxdeg + 1);
        this.mseTest = new Array(this.maxdeg + 1);
        let lo = Infinity, hi = -Infinity;
        for (let d = 0; d <= this.maxdeg; d++) {
            this.mseTrain[d] = this._mse(this.train, d);
            this.mseTest[d] = this._mse(this.test, d);
            lo = Math.min(lo, this.mseTrain[d], this.mseTest[d]);
            hi = Math.max(hi, this.mseTrain[d], this.mseTest[d]);
        }
        lo = Math.max(lo, 1e-6);
        this.logMin = Math.floor(Math.log10(lo));
        this.logMax = Math.ceil(Math.log10(hi));
        if (this.logMax <= this.logMin) this.logMax = this.logMin + 1;
        // Cap the visible span: a degree-15 fit can send test MSE to the moon, which
        // would squash the informative low-degree region into a sliver. Bound the
        // axis to ~6 decades; anything beyond pins to the top edge (msy clamps),
        // reading as "the error shoots off the chart".
        this.logMax = Math.min(this.logMax, this.logMin + 6);
    }

    _fitPixels(d) {
        const arr = new Array(this.gx.length);
        for (let i = 0; i < this.gx.length; i++) arr[i] = this._clampPix(this.sy(this.fit.eval(this.xgrid[i], d)));
        return arr;
    }

    // --- structure ---
    _build() {
        this.replaceChildren();
        const wrap = ofEl("div", "of-wrap");

        // Main plot.
        this.mainSvg = svg("svg", {
            class: "of-svg of-main", viewBox: `0 0 ${this.W} ${this.H}`,
            role: "img", "aria-label": ofT("of.aria", "Ilustração interativa de sobreajuste em regressão polinomial"),
        });
        const defs = svg("defs");
        const clip = svg("clipPath", { id: `of-clip-${Math.random().toString(36).slice(2)}` });
        this.clipId = clip.getAttribute("id");
        clip.append(svg("rect", { x: this.m.l, y: this.m.t, width: this.plotW, height: this.plotH }));
        defs.append(clip);
        this.gridLayer = svg("g", { class: "of-gridlayer" });
        this.truthPath = svg("path", { class: "of-truth", "clip-path": `url(#${this.clipId})`, fill: "none" });
        this.fitPath = svg("path", { class: "of-fit", "clip-path": `url(#${this.clipId})`, fill: "none" });
        this.pointLayer = svg("g", { class: "of-pointlayer" });
        this.mainSvg.append(defs, this.gridLayer, this.truthPath, this.fitPath, this.pointLayer);

        // Legend + controls + MSE panel.
        wrap.append(this.mainSvg, this._legend(), this._controls(), this._mseHead());

        this.mseSvg = svg("svg", { class: "of-svg of-mse", viewBox: `0 0 ${this.W2} ${this.H2}`, role: "img", "aria-label": ofT("of.mse_aria", "MSE de treino e de teste em função do grau") });
        this.mseGrid = svg("g", { class: "of-gridlayer" });
        this.mseData = svg("g", { class: "of-mse-data" });
        this.mseSvg.append(this.mseGrid, this.mseData);
        wrap.append(this.mseSvg);

        this.append(wrap);

        // Initial draw.
        this._drawGridMain();
        this._drawTruth();
        this._drawPoints();
        this.curveY = this._fitPixels(this.degree);
        this._drawFit();
        this._drawGridMSE();
        this._drawMSE();
    }

    _legend() {
        const row = ofEl("div", "of-legend");
        const chip = (mod, label, dash) => {
            const c = ofEl("span", "of-chip");
            const sw = ofEl("span", "of-swatch " + mod + (dash ? " of-swatch-dash" : ""));
            c.append(sw, document.createTextNode(label));
            return c;
        };
        row.append(
            chip("of-truth", ofT("of.truth", "f (desconhecida)"), true),
            chip("of-train", ofT("of.train", "treino"), false),
            chip("of-test", ofT("of.test", "teste"), false),
        );
        return row;
    }

    _controls() {
        const bar = ofEl("div", "of-controls");
        const lab = ofEl("label", "of-deg");
        this.degEl = ofEl("span", "of-degval");
        this.degEl.textContent = this.degree;
        lab.append(document.createTextNode(ofT("of.degree", "grau") + " = "), this.degEl);

        this.slider = ofEl("input", "range of-slider");
        this.slider.type = "range";
        this.slider.min = 0; this.slider.max = this.maxdeg; this.slider.step = 1;
        this.slider.value = this.degree;
        this.slider.setAttribute("aria-label", ofT("of.degree_aria", "Grau do polinômio"));
        lab.setAttribute("for", "of-slider");
        this.slider.id = "of-slider";
        this.slider.addEventListener("input", () => this._setDegree(parseInt(this.slider.value, 10), true));

        this.resampleBtn = ofEl("button", "btn of-resample");
        this.resampleBtn.type = "button";
        this.resampleBtn.textContent = ofT("of.resample", "novo conjunto");
        this.resampleBtn.addEventListener("click", () => this._resample());

        bar.append(lab, this.slider, this.resampleBtn);
        return bar;
    }

    _mseHead() {
        const h = ofEl("div", "of-mse-head");
        const title = ofEl("span", "of-mse-title");
        title.textContent = ofT("of.mse_title", "Erro quadrático médio (MSE) por grau");
        const leg = ofEl("span", "of-mse-legend");
        const chip = (mod, label) => {
            const c = ofEl("span", "of-chip");
            c.append(ofEl("span", "of-swatch " + mod), document.createTextNode(label));
            return c;
        };
        leg.append(chip("of-train", ofT("of.mse_train", "treino")), chip("of-test", ofT("of.mse_test", "teste")));
        h.append(title, leg);
        return h;
    }

    // --- drawing ---
    _tick(x, y, text, anchor) {
        const t = svg("text", { class: "of-tick", x, y, "text-anchor": anchor });
        t.textContent = text;
        return t;
    }

    _drawGridMain() {
        const g = this.gridLayer;
        g.replaceChildren();
        const xStep = niceStep((this.xmax - this.xmin) / 6);
        const yStep = niceStep((this.ymax - this.ymin) / 5);
        for (let x = Math.ceil(this.xmin / xStep) * xStep; x <= this.xmax + 1e-9; x += xStep) {
            const px = this.sx(x);
            if (this.showGrid) g.append(svg("line", { class: "of-grid", x1: px, y1: this.m.t, x2: px, y2: this.m.t + this.plotH }));
            g.append(this._tick(px, this.m.t + this.plotH + 15, fmt(x), "middle"));
        }
        for (let y = Math.ceil(this.ymin / yStep) * yStep; y <= this.ymax + 1e-9; y += yStep) {
            const py = this.sy(y);
            if (this.showGrid) g.append(svg("line", { class: "of-grid", x1: this.m.l, y1: py, x2: this.m.l + this.plotW, y2: py }));
            g.append(this._tick(this.m.l - 8, py + 4, fmt(y), "end"));
        }
        if (this.ymin <= 0 && this.ymax >= 0) {
            const py = this.sy(0);
            g.append(svg("line", { class: "of-axis", x1: this.m.l, y1: py, x2: this.m.l + this.plotW, y2: py }));
        }
    }

    _drawTruth() {
        let d = "";
        for (let i = 0; i < this.gx.length; i++) {
            const py = this.sy(runge(this.xgrid[i]));
            d += (i ? " L" : "M") + this.gx[i].toFixed(1) + " " + py.toFixed(1);
        }
        this.truthPath.setAttribute("d", d);
    }

    _drawPoints() {
        this.pointLayer.replaceChildren();
        for (const p of this.test) this.pointLayer.append(svg("circle", { class: "of-pt of-test", cx: this.sx(p.x), cy: this.sy(p.y), r: 4 }));
        for (const p of this.train)  {
            const pClass = p.x !== this.xfixed ? "of-pt of-train" : "of-pt of-fixed"
            this.pointLayer.append(svg("circle", { class: pClass, cx: this.sx(p.x), cy: this.sy(p.y), r: 4 }));
        }
    }

    _drawFit() {
        let d = "";
        for (let i = 0; i < this.gx.length; i++) d += (i ? " L" : "M") + this.gx[i].toFixed(1) + " " + this.curveY[i].toFixed(1);
        this.fitPath.setAttribute("d", d);
    }

    _drawGridMSE() {
        const g = this.mseGrid;
        g.replaceChildren();
        for (let k = this.logMin; k <= this.logMax; k++) {
            const py = this.msy(Math.pow(10, k));
            if (this.showGrid) g.append(svg("line", { class: "of-grid", x1: this.m2.l, y1: py, x2: this.m2.l + this.mplotW, y2: py }));
            const lab = svg("text", { class: "of-tick", x: this.m2.l - 8, y: py + 4, "text-anchor": "end" });
            lab.textContent = "10" + ofSup(k);
            g.append(lab);
        }
        for (let d = 0; d <= this.maxdeg; d++) {
            const px = this.msx(d);
            if (this.showGrid) g.append(svg("line", { class: "of-grid of-grid-faint", x1: px, y1: this.m2.t, x2: px, y2: this.m2.t + this.mplotH }));
            if (d % 5 === 0 || d === this.maxdeg) {
                g.append(this._tick(px, this.m2.t + this.mplotH + 15, String(d), "middle"));
            }
        }
        const xt = svg("text", { class: "of-axis-title", x: this.m2.l + this.mplotW / 2, y: this.H2 - 6, "text-anchor": "middle" });
        xt.textContent = ofT("of.degree", "grau");
        g.append(xt);
    }

    // Reveal MSE points for degrees 0..current — the set grows as the slider rises.
    _drawMSE() {
        const g = this.mseData;
        g.replaceChildren();
        const d = this.degree;
        const series = (arr, mod) => {
            if (d >= 1) {
                let pts = "";
                for (let k = 0; k <= d; k++) pts += this.msx(k).toFixed(1) + "," + this.msy(arr[k]).toFixed(1) + " ";
                g.append(svg("polyline", { class: "of-mse-line " + mod, points: pts.trim(), fill: "none" }));
            }
            for (let k = 0; k <= d; k++) {
                const cur = k === d;
                g.append(svg("circle", {
                    class: "of-mse-dot " + mod + (cur ? " of-dot-new" : ""),
                    cx: this.msx(k), cy: this.msy(arr[k]), r: cur ? 4.5 : 3,
                }));
            }
        };
        series(this.mseTrain, "of-train");
        series(this.mseTest, "of-test");
    }

    // --- interaction ---
    _setDegree(d, animate) {
        d = Math.max(0, Math.min(d, this.maxdeg));
        this.degree = d;
        this.degEl.textContent = d;
        const target = this._fitPixels(d);
        if (!animate || this._reduceMotion || !this.curveY) {
            if (this._raf) { cancelAnimationFrame(this._raf); this._raf = null; }
            this.curveY = target;
            this._drawFit();
        } else {
            this._animateTo(target);
        }
        this._drawMSE();
    }

    _animateTo(target) {
        if (this._raf) cancelAnimationFrame(this._raf);
        const from = this.curveY.slice();
        const start = performance.now();
        const dur = 300;
        const ease = (t) => 1 - Math.pow(1 - t, 3); // easeOutCubic
        const step = (now) => {
            const t = Math.min(1, (now - start) / dur);
            const e = ease(t);
            for (let i = 0; i < target.length; i++) this.curveY[i] = from[i] + (target[i] - from[i]) * e;
            this._drawFit();
            this._raf = t < 1 ? requestAnimationFrame(step) : null;
        };
        this._raf = requestAnimationFrame(step);
    }

    _resample() {
        this._generate();
        this._drawPoints();
        this._drawGridMSE();      // log-axis bounds may have shifted
        const target = this._fitPixels(this.degree);
        if (this._reduceMotion || !this.curveY) { this.curveY = target; this._drawFit(); }
        else this._animateTo(target);
        this._drawMSE();
    }
}

if (!customElements.get("delta-overfitting")) {
    customElements.define("delta-overfitting", Overfitting);
}


class KnnIllustrator extends HTMLElement {
    connectedCallback() {
        if(this.dataset.deltaReady === "1") return;
        this.dataset.deltaReady = "1"
        // Geometry / data window (all overridable via attributes).
        this.xmin = this._num("xmin", -1);
        this.xmax = this._num("xmax", 1);
        this.ymin = this._num("ymin", -0.3);
        this.ymax = this._num("ymax", 1.2);
        this.k =  this._num("k",3)
        this.lineMap = {}

        this.W = 640;
        this.H = 400;
        this.m = { l: 46, r: 16, t: 16, b: 34 };
        this.plotW = this.W - this.m.l - this.m.r;
        this.plotH = this.H - this.m.t - this.m.b;

        this.showRunge = this.getAttribute("runge") !== "false";
        this.showGrid = this.getAttribute("grid") !== "false"; // grid="false" to hide
        this.points = this._initialPoints();
        this.pointsAdded = [];
        this.drag = null;
        this.justDragged = false;

        this._build()
    }

    // --- drawing ---
    _drawGrid() {
        const g = this.gridLayer;
        g.replaceChildren();

        const xStep = niceStep((this.xmax - this.xmin) / 6);
        const yStep = niceStep((this.ymax - this.ymin) / 5);

        for (let x = Math.ceil(this.xmin / xStep) * xStep; x <= this.xmax + 1e-9; x += xStep) {
            const px = this.sx(x);
            if (this.showGrid) g.append(svg("line", { class: "pi-gridline", x1: px, y1: this.m.t, x2: px, y2: this.m.t + this.plotH }));
            g.append(this._label(px, this.m.t + this.plotH + 16, fmt(x), "middle"));
        }
        for (let y = Math.ceil(this.ymin / yStep) * yStep; y <= this.ymax + 1e-9; y += yStep) {
            const py = this.sy(y);
            if (this.showGrid) g.append(svg("line", { class: "pi-gridline", x1: this.m.l, y1: py, x2: this.m.l + this.plotW, y2: py }));
            g.append(this._label(this.m.l - 8, py + 4, fmt(y), "end"));
        }

        // Emphasised axes at x = 0 / y = 0 when in view.
        if (this.ymin <= 0 && this.ymax >= 0) {
            const py = this.sy(0);
            g.append(svg("line", { class: "pi-axis", x1: this.m.l, y1: py, x2: this.m.l + this.plotW, y2: py }));
        }
        if (this.xmin <= 0 && this.xmax >= 0) {
            const px = this.sx(0);
            g.append(svg("line", { class: "pi-axis", x1: px, y1: this.m.t, x2: px, y2: this.m.t + this.plotH }));
        }
    }
    // --- coordinate mapping ---
    sx(x) { return this.m.l + ((x - this.xmin) / (this.xmax - this.xmin)) * this.plotW; }
    sy(y) { return this.m.t + ((this.ymax - y) / (this.ymax - this.ymin)) * this.plotH; }
    dx(px) { return this.xmin + ((px - this.m.l) / this.plotW) * (this.xmax - this.xmin); }
    dy(py) { return this.ymax - ((py - this.m.t) / this.plotH) * (this.ymax - this.ymin); }
    
  _label(x, y, text, anchor) {
        const t = svg("text", { class: "pi-tick", x, y, "text-anchor": anchor });
        t.textContent = text;
        return t;
    }
    _num(name, dflt) {
        const v = parseFloat(this.getAttribute(name));
        return Number.isFinite(v) ? v : dflt;
    }
     clientToData(evt) {
        const pt = this.svgEl.createSVGPoint();
        pt.x = evt.clientX;
        pt.y = evt.clientY;
        const p = pt.matrixTransform(this.svgEl.getScreenCTM().inverse());
        return { x: this.dx(p.x), y: this.dy(p.y) };
    }
    _build() {
        this.classList.add("pi");
        this.replaceChildren();

        const wrap = document.createElement("div");
        wrap.className = "pi-wrap";

        this.svgEl = svg("svg", {
            class: "pi-svg",
            viewBox: `0 0 ${this.W} ${this.H}`,
            role: "img",
            "aria-label": "Ilustração interativa de interpolação polinomial",
        });

        this.pointLayer = svg("g", { class: "pi-points" });
        this.gridLayer =  svg("g", {class: "pi-grid"})
        this.svgEl.append(this.gridLayer, this.pointLayer);

        // Background rectangle captures clicks (to add points).
        this.bg = svg("rect", {
            class: "pi-bg", x: this.m.l, y: this.m.t, width: this.plotW, height: this.plotH,
            fill: "transparent",
        });
        this.svgEl.insertBefore(this.bg,this.pointLayer)
        this.bg.addEventListener("click", (e) => this._onAdd(e));

        wrap.append(this.svgEl);
        //wrap.append(this._controls());
        this.append(wrap);

        this._drawGrid()
        this._render()

    }

    _controls() {}

    _drawGrid() {
        const g = this.gridLayer;
        g.replaceChildren();

        const xStep = niceStep((this.xmax - this.xmin) / 6);
        const yStep = niceStep((this.ymax - this.ymin) / 5);

        for (let x = Math.ceil(this.xmin / xStep) * xStep; x <= this.xmax + 1e-9; x += xStep) {
            const px = this.sx(x);
            if (this.showGrid) g.append(svg("line", { class: "pi-gridline", x1: px, y1: this.m.t, x2: px, y2: this.m.t + this.plotH }));
            g.append(this._label(px, this.m.t + this.plotH + 16, fmt(x), "middle"));
        }
        for (let y = Math.ceil(this.ymin / yStep) * yStep; y <= this.ymax + 1e-9; y += yStep) {
            const py = this.sy(y);
            if (this.showGrid) g.append(svg("line", { class: "pi-gridline", x1: this.m.l, y1: py, x2: this.m.l + this.plotW, y2: py }));
            g.append(this._label(this.m.l - 8, py + 4, fmt(y), "end"));
        }

        // Emphasised axes at x = 0 / y = 0 when in view.
        if (this.ymin <= 0 && this.ymax >= 0) {
            const py = this.sy(0);
            g.append(svg("line", { class: "pi-axis", x1: this.m.l, y1: py, x2: this.m.l + this.plotW, y2: py }));
        }
        if (this.xmin <= 0 && this.xmax >= 0) {
            const px = this.sx(0);
            g.append(svg("line", { class: "pi-axis", x1: px, y1: this.m.t, x2: px, y2: this.m.t + this.plotH }));
        }
    }

    _onDragStart(e,i) {
        e.preventDefault();
        e.stopPropagation();
        this.drag = i;
        const circle = e.currentTarget;
        circle.setPointerCapture(e.pointerId);

        const move = (ev) => {
            let { x, y } = this.clientToData(ev);
            x = Math.min(this.xmax, Math.max(this.xmin, x));
            y = Math.min(this.ymax, Math.max(this.ymin, y));
            this.pointsAdded[this.drag] = { x, y };
            circle.setAttribute("cx", this.sx(x));
            circle.setAttribute("cy", this.sy(y));
            const index = circle.getAttribute("index")
            const lines = this.lineMap[index]
            lines.forEach(line => line.remove())
            this._classify(circle)

        };
        const up = (ev) => {
            circle.releasePointerCapture(ev.pointerId);
            circle.removeEventListener("pointermove", move);
            circle.removeEventListener("pointerup", up);
            this.drag = null;
            this.justDragged = true;
        };
        circle.addEventListener("pointermove", move);
        circle.addEventListener("pointerup", up);
    }

    _onAdd(e) {
        const p = this.clientToData(e)
        const g =  this.pointLayer
        const pointIndex = this.pointsAdded.length+1
        const point = svg("circle", {
            class: "pi-unclassified-point",
            cx : this.sx(p.x),
            cy: this.sy(p.y),
            r: 7,
            index : pointIndex
        })

        point.addEventListener("pointerdown", (e) => {
            this._onDragStart(e, pointIndex)
        })

        this.pointsAdded.push(point)

        g.appendChild(point)

        this._classify(point)

    }

    _initialPoints() {
        const points  = []
        const rangeA = [(this.xmax - this.xmin)/2,(this.ymax - this.ymin)*0.4]

        const rangeB = [(this.xmax-this.xmin)*0.9, (this.ymax - this.ymin)*0.75]

        for(var i = 0; i < 50; i++) {
            // range A
            const p_A = svg("circle",{
                cx: this.sx(this.xmin + Math.random()*rangeA[0]), 
                cy: this.sy(this.ymin + Math.random()*rangeA[1]), 
                r : 6,
                class: "pi-point", 
                "data-accent" : "orange"})
            points.push(p_A)
            // range B
            const x = this.xmin + rangeB[0]*(0.35+Math.random());
            const y = this.ymin + rangeB[1]*Math.random();
            points.push(svg("circle", {
                cx : this.sx(x),
                cy : this.sy(y),
                r : 6,
                class : "pi-point b",
                "data-accent" : "purple"
            }))
        }
        return points

    }

    _render() {
        const g = this.pointLayer;
        this.points.forEach(p => {
            g.appendChild(p)
        })
    }

    _distance(u,v) {
        const deltaX =  u.getAttribute("cx") - v.getAttribute("cx")
        const deltaY =  u.getAttribute("cy") - v.getAttribute("cy")
        return Math.hypot( deltaX, deltaY)
    }

    _connectPoints(p1,p2) {
        const g = this.gridLayer
        const line = svg("line", {
            x1 : p1.getAttribute("cx"),
            y1 : p1.getAttribute("cy"),
            x2 : p2.getAttribute("cx"),
            y2 : p2.getAttribute("cy"),
            class: "pi-runge"
        })
        if(this.lineMap[p1.getAttribute("index")]!== undefined) {
            this.lineMap[p1.getAttribute("index")].push(line)
        } else {
            this.lineMap[p1.getAttribute("index")] = []
            this.lineMap[p1.getAttribute("index")].push(line)
        }
        g.appendChild(line)


    }
    _classify(new_point) {
        let distances = []
        this.points.forEach((point,i) => {
            distances.push({distance:this._distance(new_point, point), index: i, "data-accent" : point.getAttribute("data-accent")})
        })
        distances = distances.sort((a,b) => a.distance - b.distance)

        const class_counter = {}
        for(let i = 0; i< this.k; i++) {
            class_counter[distances[i]["data-accent"]] = class_counter[distances[i]["data-accent"]] ? class_counter[distances[i]["data-accent"]] + 1 : 1
            this._connectPoints(new_point, this.points[distances[i].index])
        }
        let max_class_label = ""
        let max_class = 0
        Object.entries(class_counter).forEach(([label, count]) => {
            if(max_class) {
                if(max_class < count) {
                    max_class_label = label
                }
            } else {
                max_class_label = label
                max_class = count
            }
        })
        new_point.classList.add("pi-point")
        new_point.setAttribute("data-accent", max_class_label)

        // connect to nearest neighbors
        
    }
}

customElements.define("delta-knn-example",KnnIllustrator)